import { useEffect, useState } from "react";
import API from "../../api/axios";
import DashboardLayout from "../../layouts/DashboardLayout";
import {
  Button,
  TextField,
  Typography,
  Box,
  Card,
  CardContent,
} from "@mui/material";
import { useNavigate } from "react-router-dom";

export default function Projects() {
  const navigate = useNavigate();

  const [projectForm, setProjectForm] = useState({
    name: "",
    description: "",
    start_date: "",
    end_date: "",
  });

  const [userForm, setUserForm] = useState({
    username: "",
    password: "",
  });

  const createProject = async () => {
    await API.post("projects/create/", projectForm);
    alert("Project Created ✅");
  };

  const createProjectUser = async () => {
    await API.post("create-user/", userForm);
    alert("User Added ✅");
  };

  return (
    <DashboardLayout>
      {/* 🔥 CARDS */}
      <Box
        sx={{
          display: "flex",
          gap: 4,
          flexWrap: "wrap",
        }}
      >
        {/* LEFT CARD */}
        <Card
          sx={{
            flex: 1,
            minWidth: 320,
            p: 2,
            borderRadius: 4,
            background: "linear-gradient(135deg, #1e3c72, #2a5298)",
            color: "#fff",
            boxShadow: "0 20px 40px rgba(0,0,0,0.3)",
            transform: "perspective(1000px) rotateX(5deg)",
            transition: "0.4s",
            "&:hover": {
              transform: "perspective(1000px) rotateX(0deg) scale(1.02)",
            },
          }}
        >
          <CardContent>
            <Typography variant="h6" mb={2}>
              Create Project User
            </Typography>

            {/* USERNAME */}
            <TextField
              fullWidth
              label="Username"
              margin="normal"
              InputLabelProps={{ style: { color: "#fff" } }}
              sx={{ input: { color: "#fff" } }}
              onChange={(e) =>
                setUserForm({ ...userForm, username: e.target.value })
              }
            />

            {/* PASSWORD */}
            <TextField
              fullWidth
              label="Password"
              type="password"
              margin="normal"
              InputLabelProps={{ style: { color: "#fff" } }}
              sx={{ input: { color: "#fff" } }}
              onChange={(e) =>
                setUserForm({ ...userForm, password: e.target.value })
              }
            />

            {/* 🔥 BUTTON EXACTLY BELOW PASSWORD */}
            <Button
              fullWidth
              variant="contained"
              sx={{
                mt: 3, // 🔥 spacing important
                py: 1.5,
                fontWeight: "bold",
                background: "linear-gradient(45deg, #ff512f, #dd2476)",
                boxShadow: "0 10px 25px rgba(0,0,0,0.3)",
                transition: "0.3s",
                "&:hover": {
                  transform: "scale(1.02)",
                },
              }}
              onClick={createProjectUser}
            >
              ADD PROJECT USER
            </Button>
          </CardContent>
        </Card>

        {/* RIGHT CARD */}
        <Card
          sx={{
            flex: 1,
            minWidth: 320,
            p: 2,
            borderRadius: 4,
            background: "linear-gradient(135deg, #0f2027, #203a43)",
            color: "#fff",
            boxShadow: "0 20px 40px rgba(0,0,0,0.3)",
            transform: "perspective(1000px) rotateX(5deg)",
            transition: "0.4s",
            "&:hover": {
              transform: "perspective(1000px) rotateX(0deg) scale(1.02)",
            },
          }}
        >
          <CardContent>
            <Typography variant="h6">Create Project User</Typography>

            <TextField
              fullWidth
              label="Username"
              margin="normal"
              InputLabelProps={{ style: { color: "#fff" } }}
              sx={{ input: { color: "#fff" } }}
              onChange={(e) =>
                setUserForm({ ...userForm, username: e.target.value })
              }
            />

            <TextField
              fullWidth
              label="Password"
              type="password"
              margin="normal"
              InputLabelProps={{ style: { color: "#fff" } }}
              sx={{ input: { color: "#fff" } }}
              onChange={(e) =>
                setUserForm({ ...userForm, password: e.target.value })
              }
            />

            <Button
              fullWidth
              variant="contained"
              sx={{
                mt: 2,
                background: "linear-gradient(45deg, #ff512f, #dd2476)",
              }}
              onClick={createProjectUser}
            >
              Add Project User
            </Button>
          </CardContent>
        </Card>
      </Box>

      {/* 🔥 SINGLE BUTTON (NOT INSIDE MAP ❌) */}
      <Box mt={6} textAlign="center">
        <Button
          variant="contained"
          sx={{
            px: 6,
            py: 1.5,
            borderRadius: 3,
            fontSize: "16px",
            background: "linear-gradient(45deg, #00c6ff, #0072ff)",
            boxShadow: "0 10px 25px rgba(0,0,0,0.3)",
          }}
          onClick={() => navigate("/admin/projects/list")}
        >
          View Project List
        </Button>
      </Box>
    </DashboardLayout>
  );
}
